insert into question_modules (id,title,eyebrow,description,target_question_count) values ('driver-licensing','Learn Driver Licensing lesson by lesson.','Driver Licensing module','Study SPSV driver licensing in focused lessons, practise original FREE_NOW questions, review mistakes, and finish with a mixed 30-question test.',30) on conflict (id) do update set title=excluded.title, eyebrow=excluded.eyebrow, description=excluded.description, target_question_count=excluded.target_question_count;
