-- Seed for driver-licensing generated from verified FREE_NOW question bank
create table if not exists question_modules (id text primary key, title text, eyebrow text, description text, target_question_count int);
create table if not exists question_lessons (id text primary key, module_id text, title text, intro text, memory_trick text, is_final_test boolean default false);
create table if not exists question_bank (id text primary key, module_id text, lesson_id text, question_number int, question_text text, question_type text, options jsonb, correct_answers jsonb, explanation text, memory_tip text, common_mistake text, tags jsonb, source text);
